Paste the `UserList` component (and how it gets `users`), and I’ll mark exactly what to change.

Until then, here are two “drop-in” fixes you can use right away. Pick the one that matches how `UserList` gets its data.

---

## 1) If `UserList` gets `users` as a prop

Original (likely):

```jsx
function UserList({ users }) {
  return (
    <div>
      {users.map(user => (              // <-- crash here when users is undefined
        <UserCard key={user.id} user={user} />
      ))}
    </div>
  );
}
```

Change it to:

```jsx
function UserList({ users }) {
  const safeUsers = Array.isArray(users) ? users : [];

  return (
    <div>
      {safeUsers.map(user => (
        <UserCard key={user.id} user={user} />
      ))}
    </div>
  );
}
```

Or even shorter:

```jsx
function UserList({ users }) {
  return (
    <div>
      {Array.isArray(users) &&
        users.map(user => (
          <UserCard key={user.id} user={user} />
        ))}
    </div>
  );
}
```

That alone prevents `cannot read property 'map' of undefined`.

---

## 2) If `UserList` does its own API call with state

Original (likely):

```jsx
function UserList() {
  const [users, setUsers] = useState();  // <-- starts as undefined

  useEffect(() => {
    apiCall().then(data => setUsers(data.users));
  }, []);

  return (
    <div>
      {users.map(user => (               // <-- crash here
        <UserCard key={user.id} user={user} />
      ))}
    </div>
  );
}
```

Change it to:

```jsx
function UserList() {
  const [users, setUsers] = useState([]);  // start as empty array

  useEffect(() => {
    apiCall().then(data => {
      setUsers(Array.isArray(data.users) ? data.users : []);
    });
  }, []);

  return (
    <div>
      {users.map(user => (
        <UserCard key={user.id} user={user} />
      ))}
    </div>
  );
}
```

That’s it: initializing with `[]` + the `Array.isArray` check makes `.map` safe.

